import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { JobProvider } from './context/JobContext';  // Add this import
import Navbar from './components/Navbar';
import Dashboard from './pages/Dashboard';
import AddJob from './pages/AddJob'; 
import JobDetails from './pages/JobDetails';

function App() {
  return (
    <JobProvider>  {/* Wrap everything with JobProvider */}
      <Router>
        <div style={{ 
          background: 'linear-gradient(145deg, #e0f7f5 0%, #c5e3ed 100%)',
          minHeight: '100vh',
          position: 'relative'
        }}>
          {/* Abstract pattern overlay */}
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: `
              radial-gradient(circle at 20% 30%, rgba(9,124,127,0.1) 0%, transparent 30%),
              radial-gradient(circle at 80% 70%, rgba(50,103,132,0.1) 0%, transparent 40%),
              repeating-linear-gradient(45deg, rgba(9,124,127,0.02) 0px, rgba(9,124,127,0.02) 2px, transparent 2px, transparent 10px)
            `,
            pointerEvents: 'none',
            zIndex: 0
          }} />

          {/* Content */}
          <div style={{ position: 'relative', zIndex: 10 }}>
            <Navbar />
            <Routes>
              <Route path="/" element={<Dashboard />} />
              <Route path="/add" element={<AddJob />} />  
              <Route path="/job/:id" element={<JobDetails />} /> 
              <Route path="/edit/:id" element={<JobDetails />} />
            </Routes>
          </div>
        </div>
      </Router>
    </JobProvider>
  );
}

export default App;
